+@using Microsoft.AspNetCore.Components.Forms
+
+<div class="file-drop-zone @(_isDragOver ? "drag-over" : "")"
+     @ondragenter="HandleDragEnter"
+     @ondragover="HandleDragOver"
+     @ondragleave="HandleDragLeave"
+     @ondrop="HandleDrop">
+    <InputFile @ref="_inputFile"
+               OnChange="HandleFileSelection"
+               multiple
+               class="file-input-hidden"
+               id="@_inputId" />
+    <p>Drag &amp; drop files here</p>
+</div>
+
+@if (_entries.Count > 0)
+{
+    <ul class="file-list">
+        @foreach (var entry in _entries)
+        {
+            <li class="file-entry @(entry.HasError ? "file-error" : "")">
+                @if (entry.HasError)
+                {
+                    <span class="file-error-message">@entry.ErrorMessage</span>
+                }
+                else
+                {
+                    <span class="file-name">@entry.Info!.Name</span>
+                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
+                    <span class="file-type">@entry.Info.Type</span>
+                }
+                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB
+
+    private bool _isDragOver;
+    private InputFile? _inputFile;
+    private string _inputId = $"file-input-{Guid.NewGuid():N}";
+    private readonly List<FileEntry> _entries = new();
+
+    [Parameter]
+    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }
+
+    private void HandleDragEnter() => _isDragOver = true;
+    private void HandleDragOver() => _isDragOver = true;
+    private void HandleDragLeave() => _isDragOver = false;
+
+    private async Task HandleDrop()
+    {
+        _isDragOver = false;
+        // Drop is handled via InputFile's OnChange
+        await Task.CompletedTask;
+    }
+
+    private async Task HandleFileSelection(InputFileChangeEventArgs e)
+    {
+        foreach (var file in e.GetMultipleFiles(int.MaxValue))
+        {
+            if (file.Size > MaxFileSize)
+            {
+                _entries.Add(new FileEntry
+                {
+                    HasError = true,
+                    ErrorMessage = $"\"{file.Name}\" exceeds the 10 MB limit ({FormatSize(file.Size)})"
+                });
+            }
+            else
+            {
+                var info = new FileInfo(file.Name, file.Size, file.ContentType);
+                _entries.Add(new FileEntry { Info = info });
+            }
+        }
+
+        await NotifyParent();
+    }
+
+    private async Task Remove(FileEntry entry)
+    {
+        _entries.Remove(entry);
+        await NotifyParent();
+    }
+
+    private async Task NotifyParent()
+    {
+        var accepted = _entries
+            .Where(e => !e.HasError && e.Info is not null)
+            .Select(e => e.Info!)
+            .ToList();
+        await OnFilesChanged.InvokeAsync(accepted);
+    }
+
+    private static string FormatSize(long bytes) => bytes switch
+    {
+        < 1024 => $"{bytes} B",
+        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
+        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
+    };
+
+    private class FileEntry
+    {
+        public FileInfo? Info { get; init; }
+        public bool HasError { get; init; }
+        public string? ErrorMessage { get; init; }
+    }
+}
