.file-drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    padding: 2rem;
    transition: border-color 0.2s, background-color 0.2s;
    position: relative;
    cursor: pointer;
}

.file-drop-zone p {
    margin: 0;
    color: #6c757d;
    font-size: 1rem;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.file-input-hidden {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-name {
    font-weight: 500;
    flex: 1;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.file-error-message {
    color: #dc3545;
    flex: 1;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
    margin-left: auto;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

